import React from "react";

const Button = ({ children }) => (
  <button className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 m-2 rounded-xl shadow">
    {children}
  </button>
);

export default function Dashboard({ user }) {
  return (
    <div className="h-screen bg-green-50 flex flex-col items-center justify-center">
      <h1 className="text-3xl font-bold text-green-700 mb-6">
        Willkommen, {user.username}!
      </h1>
      <div className="flex">
        <Button>Judging</Button>
        <Button>Teilnehmer</Button>
        <Button>Übersicht</Button>
      </div>
    </div>
  );
}
